from collections import defaultdict
message_history = defaultdict(list)

def loop_detector(content, sender):
    msg_hash = hash(content[:200])
    history = message_history[sender]
    if msg_hash in history[-3:]:
        return {'loop_detected': True, 'reset_context': True}
    history.append(msg_hash)
    return None

groupchat.register_reply([GroupChatManager], reply=loop_detector)

