conversation_summary = ''

def drift_scanner(content, sender):
    global conversation_summary
    # Update summary every 5 messages
    if len(conversation_summary) < 1000:
        conversation_summary += content[:200] + '\n'

    # Check if response contradicts summary
    contradictions = re.findall(r'(no|wrong|incorrect|not|disagree)', content.lower())
    if len(contradictions) > 3:
        return {'drift_detected': True, 'score': len(contradictions)}
    return None

