import json
from collections import deque

class ContextManager:
    def __init__(self, max_items=10):
        self.state = {}
        self.recent_msgs = deque(maxlen=max_items)

    def update(self, content, sender):
        self.recent_msgs.append({'sender': sender, 'content': content})
        # Extract key facts
        self.state['last_decision'] = content[-100:]
        self.state['agent_count'] = len(set(m['sender'] for m in self.recent_msgs))

    def get_context(self):
        return json.dumps(self.state) + '\nRecent: ' + str(list(self.recent_msgs)[-3:])

ctx_mgr = ContextManager()
def managed_reply(content, sender):
    ctx_mgr.update(content, sender)
    return ctx_mgr.get_context()

groupchat.register_reply([GroupChatManager], reply=managed_reply)
